def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' not in line:
            continue
        k, v = line.split(':', 1)
        k = k.strip().lower().replace(' ', '_')
        v = v.strip().replace(',', '').replace('$', '')
        if k in ('credit_limit', 'balance') and v.lstrip('-').isdigit():
            out[k] = int(v)
    return out
